namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Status { get; set; } = "Pending";
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public DateTime? EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;
}

using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber);
    Task UpdateStatusAsync(int id, string newStatus);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentHttpService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await _http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var response = await _http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode)
            return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task UpdateStatusAsync(int id, string newStatus)
    {
        await _http.PutAsJsonAsync($"api/shipments/{id}/status", new { Status = newStatus });
    }
}

using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Services;

public class ShipmentServerService : IShipmentService
{
    private static readonly List<Shipment> Shipments =
    [
        new() { Id = 1, TrackingNumber = "TRK-001", Status = "In Transit", Origin = "New York", Destination = "London", EstimatedDelivery = DateTime.UtcNow.AddDays(3), CustomerEmail = "alice@example.com", CreatedAt = DateTime.UtcNow.AddDays(-2) },
        new() { Id = 2, TrackingNumber = "TRK-002", Status = "Delivered", Origin = "Tokyo", Destination = "Sydney", EstimatedDelivery = DateTime.UtcNow.AddDays(-1), CustomerEmail = "bob@example.com", CreatedAt = DateTime.UtcNow.AddDays(-5) },
        new() { Id = 3, TrackingNumber = "TRK-003", Status = "Pending", Origin = "Berlin", Destination = "São Paulo", EstimatedDelivery = DateTime.UtcNow.AddDays(7), CustomerEmail = "carlos@example.com", CreatedAt = DateTime.UtcNow.AddDays(-1) },
        new() { Id = 4, TrackingNumber = "TRK-004", Status = "In Transit", Origin = "Shanghai", Destination = "Los Angeles", EstimatedDelivery = DateTime.UtcNow.AddDays(5), CustomerEmail = "diana@example.com", CreatedAt = DateTime.UtcNow.AddDays(-3) },
        new() { Id = 5, TrackingNumber = "TRK-005", Status = "Out for Delivery", Origin = "Mumbai", Destination = "Dubai", EstimatedDelivery = DateTime.UtcNow, CustomerEmail = "eve@example.com", CreatedAt = DateTime.UtcNow.AddDays(-4) },
    ];

    private static int _nextId = 6;

    public Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return Task.FromResult(Shipments.ToList());
    }

    public Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = Shipments.FirstOrDefault(s =>
            s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult(shipment);
    }

    public Task UpdateStatusAsync(int id, string newStatus)
    {
        var shipment = Shipments.FirstOrDefault(s => s.Id == id);
        if (shipment is not null)
        {
            shipment.Status = newStatus;
        }
        return Task.CompletedTask;
    }
}

