@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<div class="container mt-4">
    <h2>Dispatcher Dashboard</h2>

    @if (_shipments is null)
    {
        <p><em>Loading shipments...</em></p>
    }
    else
    {
        <div class="mb-3">
            <input type="text" class="form-control" placeholder="Filter by destination..."
                   @bind="_filterText" @bind:event="oninput" />
        </div>

        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Action</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td>@shipment.TrackingNumber</td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(shipment.Status)">
                                @shipment.Status
                            </span>
                        </td>
                        <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width:auto;display:inline-block"
                                    value="@shipment.Status"
                                    @onchange="(e) => UpdateStatus(shipment, e.Value?.ToString())">
                                <option value="Pending">Pending</option>
                                <option value="In Transit">In Transit</option>
                                <option value="Out for Delivery">Out for Delivery</option>
                                <option value="Delivered">Delivered</option>
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    }
</div>

@code {
    private List<Shipment>? _shipments;
    private string _filterText = string.Empty;

    private IEnumerable<Shipment> FilteredShipments =>
        _shipments?.Where(s => string.IsNullOrEmpty(_filterText)
            || s.Destination.Contains(_filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        _shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(Shipment shipment, string? newStatus)
    {
        if (!string.IsNullOrEmpty(newStatus))
        {
            await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "In Transit" => "bg-info text-dark",
        "Out for Delivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        _ => "bg-light text-dark"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<div class="container mt-4">
    <h2>Track Your Shipment</h2>

    <div class="row mb-4">
        <div class="col-md-6">
            <div class="input-group">
                <input type="text" class="form-control" placeholder="Enter tracking number (e.g., TRK-001)"
                       @bind="_trackingNumber" @onkeydown="HandleKeyDown" />
                <button class="btn btn-primary" @onclick="SearchShipment" disabled="@_isSearching">
                    @if (_isSearching)
                    {
                        <span class="spinner-border spinner-border-sm" role="status"></span>
                    }
                    else
                    {
                        <span>Search</span>
                    }
                </button>
            </div>
        </div>
    </div>

    @if (_searched && _shipment is null)
    {
        <div class="alert alert-warning">
            No shipment found with tracking number "<strong>@_lastSearched</strong>".
        </div>
    }

    @if (_shipment is not null)
    {
        <div class="card">
            <div class="card-header">
                <strong>@_shipment.TrackingNumber</strong>
                <span class="badge @GetStatusBadgeClass(_shipment.Status) ms-2">@_shipment.Status</span>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6">
                        <p><strong>From:</strong> @_shipment.Origin</p>
                        <p><strong>To:</strong> @_shipment.Destination</p>
                    </div>
                    <div class="col-md-6">
                        <p><strong>Estimated Delivery:</strong>
                            @(_shipment.EstimatedDelivery?.ToString("dddd, MMMM dd, yyyy") ?? "TBD")
                        </p>
                        <p><strong>Shipped On:</strong> @_shipment.CreatedAt.ToString("MMMM dd, yyyy")</p>
                    </div>
                </div>

                @if (_shipment.Status == "Delivered")
                {
                    <div class="alert alert-success mt-3 mb-0">
                        ✅ Your shipment has been delivered!
                    </div>
                }
                else if (_shipment.EstimatedDelivery.HasValue)
                {
                    var daysLeft = (_shipment.EstimatedDelivery.Value - DateTime.UtcNow).Days;
                    <div class="alert alert-info mt-3 mb-0">
                        📅 Estimated arrival in @Math.Max(0, daysLeft) day(s).
                    </div>
                }
            </div>
        </div>
    }
