// Add additional endpoints required by the Identity /Account Razor components.
app.MapAdditionalIdentityEndpoints();

// Shipment API endpoints
var shipmentApi = app.MapGroup("api/shipments");

shipmentApi.MapGet("/", (ShipmentServerService svc) => svc.GetAllShipmentsAsync())
    .RequireAuthorization();

shipmentApi.MapGet("/track/{trackingNumber}", async (string trackingNumber, ShipmentServerService svc) =>
{
    var shipment = await svc.GetByTrackingNumberAsync(trackingNumber);
    return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
});

shipmentApi.MapPut("/{id}/status", async (int id, StatusUpdateRequest request, ShipmentServerService svc) =>
{
    await svc.UpdateStatusAsync(id, request.Status);
    return Results.NoContent();
}).RequireAuthorization();

app.Run();

public record StatusUpdateRequest(string Status);

